                                    Reply
                                </span>
                            </div>

                            <AnimatePresence>
                                {showReplyButtonId === opinion.id && (
                                    <motion.div
                                        initial={{ height: 0, opacity: 0 }}
                                        animate={{ height: "auto", opacity: 1 }}
                                        exit={{ height: 0, opacity: 0 }}
                                        transition={{ duration: 0.2 }}
                                        className="rc-reply-input-wrapper"
                                    >
                                        <textarea
                                            ref={textAreaRef}
