 18→export const addViewsController = asyncHandler(async (req, res) => {
 19→    const { journalId } = req.body;
 20→    if (!journalId) {
 21→        return res.status(400).json({ error: 'no journalId!' });
 22→    }
 23→    const viewerId = req.userId;
 24→
 25→    const { error: errorAddViews } = await supabase
 26→        .from('journal_views')
 27→        .insert({ viewer_id: viewerId, journal_id: journalId });
 28→
 29→    if (errorAddViews) {
 30→        const isDuplicateView =
 31→            errorAddViews?.code === '23505' ||
 32→            (errorAddViews?.message || '').includes('unique_journal_views');
 33→
 34→        if (isDuplicateView) {
 35→            return res.status(200).json({ message: 'success!', counted: false });
 36→        }
 37→
 38→        console.error('error:', errorAddViews.message);
 39→        return res.status(500).json({ error: 'error adding views' });
 40→    }
 41→
 42→    const { error: incrementError } = await supabase.rpc('increment_journal_view', { j_post_id: journalId });
 43→    if (incrementError) {
 44→        console.error('error incrementing journal view:', incrementError.message);
 45→        return res.status(500).json({ error: 'error incrementing views' });
 46→    }
 47→
 48→    return res.status(200).json({ message: 'success!', counted: true });
 49→});
