139→export const getPostRepliesController = asyncHandler(async (req, res) => {
140→    const { parent_id } = req.params;
141→    const { limit, before } = req.query;
142→
143→    if (!parent_id) {
144→        return res.status(400).json({ error: 'parent_id is undefined' });
145→    }
146→
147→    const parsedLimit = parseInt(limit);
148→    if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20) {
149→        return res.status(400).json({ error: 'limit should be integer or it should be between 1 to 20' });
150→    }
151→
152→    let query = supabase
153→        .from('comments')
154→        .select(COMMENT_REPLY_SELECT)
155→        .eq('parent_id', parent_id)
156→        .order('id', { ascending: false })
157→        .limit(parsedLimit + 1);
158→
159→    if (before) query = query.lt('id', before);
160→
161→    const { data, error } = await query;
162→    if (error) {
163→        console.error('supabase error while fetching replies:', error.message);
164→        return res.status(500).json({ error: 'supabase error while getting post replies' });
165→    }
166→
167→    const hasMore = data.length > parsedLimit;
168→    const slicedData = hasMore ? data.slice(0, parsedLimit) : data;
169→    return res.status(200).json({ data: slicedData, hasMore });
170→});
