### 1. Comments on Journal Posts — `addCommentService` (interactService.js:87)

**Route:** `POST /addComment` -> `addCommentController` -> `addCommentService`

**Mention handling: YES. This is the reference implementation.**

```js
// interactService.js lines 133-162
// Non-fatal: send @mention notifications
try {
    const mentionMatches = comments.match(/@([\w-]+)/g);
    if (mentionMatches && mentionMatches.length > 0) {
        const usernames = [...new Set(mentionMatches.map(m => m.slice(1)))].slice(0, 10);

        const { data: mentionedUsers } = await supabase
            .from('users')
            .select('id, username')
            .in('username', usernames);

        if (mentionedUsers && mentionedUsers.length > 0) {
            const notifs = mentionedUsers
                .filter(u => u.id !== userId && u.id !== receiverId)
                .map(u => ({
                    sender_id: userId,
                    receiver_id: u.id,
                    journal_id: postId,
                    type: 'mention',
                    read: false,
                }));

            if (notifs.length > 0) {
                await supabase.from('notifications').insert(notifs);
            }
        }
    }
} catch (mentionErr) {
    console.error('non-fatal: mention notification error', mentionErr?.message);
}
```

